require('dotenv').config();
const express = require('express');
const Database = require('better-sqlite3');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const cors = require('cors');
const path = require('path');
const fs = require('fs');
const backup = require('./backup');
const audit   = require('./audit');
const classes = require('./classes');

// ── FAIL FAST: refuse to start without JWT_SECRET ──
if (!process.env.JWT_SECRET) {
  console.error('FATAL: JWT_SECRET environment variable is not set.');
  console.error('Set it in your .env file. See .env.example for instructions.');
  process.exit(1);
}
const JWT_SECRET = process.env.JWT_SECRET;

const app = express();
const PORT = process.env.PORT || 10000;

app.use(cors());
app.use(express.json({ limit: '10mb' }));
app.use(express.static(path.join(__dirname, '../public')));

// ── DATABASE SETUP ──
const dbPath = process.env.DB_PATH || path.join(__dirname, 'school.db');
const db = new Database(dbPath);

db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    password TEXT NOT NULL,
    role TEXT NOT NULL,
    name TEXT NOT NULL,
    assigned_class TEXT,
    must_change_password INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS token_blacklist (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    token_jti TEXT UNIQUE NOT NULL,
    expires_at INTEGER NOT NULL
  );

  CREATE TABLE IF NOT EXISTS students (
    id INTEGER PRIMARY KEY,
    num INTEGER,
    student_id TEXT UNIQUE,
    name TEXT NOT NULL,
    class TEXT NOT NULL,
    gender TEXT,
    dob TEXT,
    guardian_name TEXT,
    guardian_phone TEXT,
    father_phone TEXT,
    mother_name TEXT,
    mother_phone TEXT,
    fee_amount INTEGER DEFAULT 0,
    fee_type TEXT DEFAULT 'Full payment'
  );

  CREATE UNIQUE INDEX IF NOT EXISTS idx_students_student_id ON students(student_id);

  CREATE TABLE IF NOT EXISTS promotions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    student_id INTEGER NOT NULL,
    from_class TEXT NOT NULL,
    to_class TEXT NOT NULL,
    academic_year TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'promoted',
    promoted_by TEXT,
    promoted_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS academic_settings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    key TEXT UNIQUE NOT NULL,
    value TEXT NOT NULL
  );
`);

// ── CLASS MANAGEMENT SCHEMA ──
classes.createSchema(db);

db.exec(`

  CREATE TABLE IF NOT EXISTS attendance (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    class TEXT NOT NULL,
    date TEXT NOT NULL,
    student_id INTEGER NOT NULL,
    status TEXT NOT NULL,
    locked INTEGER DEFAULT 0,
    marked_by TEXT,
    UNIQUE(class, date, student_id)
  );

  CREATE TABLE IF NOT EXISTS attendance_locks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    class TEXT NOT NULL,
    date TEXT NOT NULL,
    locked INTEGER DEFAULT 0,
    UNIQUE(class, date)
  );

  CREATE TABLE IF NOT EXISTS exam_marks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    class TEXT NOT NULL,
    subject TEXT NOT NULL,
    exam_type TEXT NOT NULL,
    academic_year TEXT NOT NULL DEFAULT '2025-2026',
    student_id INTEGER NOT NULL,
    mark REAL,
    entered_by TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(class, subject, exam_type, academic_year, student_id)
  );

  CREATE TABLE IF NOT EXISTS payments (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    class TEXT NOT NULL,
    month TEXT NOT NULL,
    student_id INTEGER NOT NULL,
    status TEXT NOT NULL,
    recorded_by TEXT,
    recorded_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(class, month, student_id)
  );
`);

audit.createSchema(db);

