// ── STUDENT ID SYSTEM ──

/**
 * generateStudentId()
 * Finds the highest existing ASS-XXXX, increments by 1.
 * Uses a transaction + UNIQUE constraint to guarantee no duplicates
 * even under concurrent requests.
 */
function generateStudentId() {
  const row = db.prepare(
    "SELECT student_id FROM students WHERE student_id LIKE 'ASS-%' ORDER BY student_id DESC LIMIT 1"
  ).get();
  if (!row) return 'ASS-0001';
  const num = parseInt(row.student_id.split('-')[1], 10);
  return 'ASS-' + String(num + 1).padStart(4, '0');
}

/**
 * validateStudentId(sid)
 * Returns true only for the format ASS-0001 through ASS-9999.
 */
function validateStudentId(sid) {
  return /^ASS-\d{4}$/.test(sid);
}

/**
 * migrateStudentIds()
 * Safe one-time migration:
 *   1. Check how many students are missing a student_id.
 *   2. Assign ASS-0001..ASS-XXXX in order of internal id.
 *   3. Wrapped in a transaction — all succeed or all roll back.
 *   4. Skips students that already have an id (idempotent).
 */
function migrateStudentIds() {
  // Handle schema migration — add column if it doesn't exist yet
  // (needed when upgrading an existing DB that was created before this code)
  const cols = db.prepare("PRAGMA table_info(students)").all().map(c => c.name);
  if (!cols.includes('student_id')) {
    db.exec("ALTER TABLE students ADD COLUMN student_id TEXT UNIQUE");
    db.exec("CREATE UNIQUE INDEX IF NOT EXISTS idx_students_student_id ON students(student_id)");
    console.log('[migration] Added student_id column to students table');
  }

  const missing = db.prepare("SELECT id FROM students WHERE student_id IS NULL ORDER BY id ASC").all();
  if (!missing.length) {
    console.log('[migration] All students already have Student IDs');
    return;
  }

  // Find the highest existing id to continue from the right number
  const row = db.prepare(
    "SELECT student_id FROM students WHERE student_id LIKE 'ASS-%' ORDER BY student_id DESC LIMIT 1"
  ).get();
  let counter = row ? parseInt(row.student_id.split('-')[1], 10) : 0;

  const update = db.prepare("UPDATE students SET student_id=? WHERE id=?");
  const migrate = db.transaction(() => {
    for (const s of missing) {
      counter++;
      update.run('ASS-' + String(counter).padStart(4, '0'), s.id);
    }
  });
  migrate();
  console.log(`[migration] Assigned Student IDs to ${missing.length} students (up to ASS-${String(counter).padStart(4,'0')})`);
}

migrateStudentIds();
