// ── AUTH MIDDLEWARE ──
function authMiddleware(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Authentication required. Please log in.' });
  try {
    const payload = jwt.verify(token, JWT_SECRET);
    // Check if token has been blacklisted (logged out)
    if (payload.jti) {
      const blacklisted = db.prepare('SELECT 1 FROM token_blacklist WHERE token_jti=?').get(payload.jti);
      if (blacklisted) return res.status(401).json({ error: 'Session expired. Please log in again.' });
    }
    req.user = payload;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Session expired. Please log in again.', code: 'TOKEN_EXPIRED' });
    }
    res.status(401).json({ error: 'Invalid session. Please log in again.' });
  }
}

function requireRole(...roles) {
  return (req, res, next) => {
    if (!roles.includes(req.user.role)) return res.status(403).json({ error: 'Forbidden' });
    next();
  };
}

// ── PASSWORD VALIDATION ──
function validatePassword(password) {
  if (!password || password.length < 8) return 'Password must be at least 8 characters.';
  if (!/[0-9]/.test(password)) return 'Password must contain at least one number.';
  return null;
}

// ── AUTH ROUTES ──
app.post('/api/login', (req, res) => {
  const { username, password, role } = req.body;
  if (!username || !password || !role)
    return res.status(400).json({ error: 'Username, password, and role are required.' });
  const user = db.prepare('SELECT * FROM users WHERE username=? AND role=?').get(username.toLowerCase(), role);
  if (!user || !bcrypt.compareSync(password, user.password)) {
    audit.log(db, { user: null, action: audit.ACTIONS.LOGIN_FAILED, targetType: 'Auth', targetId: username.toLowerCase(), details: `Failed login attempt for role: ${role}`, ip: audit.getIp(req) });
    return res.status(401).json({ error: 'Invalid username, password, or role.' });
  }
  // jti (JWT ID) enables token blacklisting on logout
  const jti = require('crypto').randomBytes(16).toString('hex');
  const token = jwt.sign(
    { id: user.id, username: user.username, role: user.role, name: user.name, jti },
    JWT_SECRET,
    { expiresIn: '7d' }
  );
  audit.log(db, { user, action: audit.ACTIONS.LOGIN_SUCCESS, targetType: 'Auth', targetId: user.username, details: `Login from ${audit.getIp(req)}`, ip: audit.getIp(req) });
  res.json({
    token,
    user: {
      id: user.id,
      username: user.username,
      role: user.role,
      name: user.name,
      must_change_password: !!user.must_change_password
    }
  });
});

// ── LOGOUT: blacklist the token ──
app.post('/api/logout', authMiddleware, (req, res) => {
  const token = req.headers.authorization?.split(' ')[1];
  try {
    const payload = jwt.decode(token);
    if (payload?.jti && payload?.exp) {
      db.prepare('INSERT OR IGNORE INTO token_blacklist (token_jti, expires_at) VALUES (?,?)')
        .run(payload.jti, payload.exp);
      // Clean up expired blacklist entries
      db.prepare('DELETE FROM token_blacklist WHERE expires_at < ?').run(Math.floor(Date.now()/1000));
    }
    audit.log(db, { user: req.user, action: audit.ACTIONS.LOGOUT, targetType: 'Auth', targetId: req.user.username, ip: audit.getIp(req) });
    res.json({ success: true });
  } catch {
    res.json({ success: true }); // Still succeed even if cleanup fails
  }
});

// ── CHANGE PASSWORD ──
app.post('/api/change-password', authMiddleware, (req, res) => {
  const { current_password, new_password } = req.body;
  if (!current_password || !new_password)
    return res.status(400).json({ error: 'Current and new password are required.' });
  const user = db.prepare('SELECT * FROM users WHERE id=?').get(req.user.id);
  if (!user || !bcrypt.compareSync(current_password, user.password))
    return res.status(401).json({ error: 'Current password is incorrect.' });
  const validationError = validatePassword(new_password);
  if (validationError) return res.status(400).json({ error: validationError });
  if (current_password === new_password)
    return res.status(400).json({ error: 'New password must be different from current password.' });
  const hash = bcrypt.hashSync(new_password, 10);
  db.prepare('UPDATE users SET password=?, must_change_password=0 WHERE id=?').run(hash, req.user.id);
  audit.log(db, { user: req.user, action: audit.ACTIONS.PASSWORD_CHANGED, targetType: 'User', targetId: req.user.username, details: 'Password changed successfully', ip: audit.getIp(req) });
  res.json({ success: true, message: 'Password changed successfully.' });
});

// ── USERS ROUTES ──
app.get('/api/users', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const users = db.prepare('SELECT id,username,role,name,assigned_class FROM users WHERE role != "superadmin"').all();
  res.json(users);
});

app.post('/api/users', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const { username, password, role, name, assigned_class } = req.body;
  if (!username || !password || !role || !name) return res.status(400).json({ error: 'Missing fields.' });
  if (req.user.role === 'admin' && role !== 'teacher') return res.status(403).json({ error: 'Admins can only create teachers.' });
  const validationError = validatePassword(password);
  if (validationError) return res.status(400).json({ error: validationError });
  try {
    const hash = bcrypt.hashSync(password, 10);
    db.prepare('INSERT INTO users (username,password,role,name,assigned_class,must_change_password) VALUES (?,?,?,?,?,?)').run(username.toLowerCase(), hash, role, name, assigned_class||null, 0);
    audit.log(db, { user: req.user, action: audit.ACTIONS.USER_CREATED, targetType: 'User', targetId: username.toLowerCase(), details: `Created ${role}: ${name}`, ip: audit.getIp(req) });
    res.json({ success: true });
  } catch (e) {
    res.status(400).json({ error: 'Username already exists' });
  }
});

app.delete('/api/users/:id', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const user = db.prepare('SELECT * FROM users WHERE id=?').get(req.params.id);
  if (!user) return res.status(404).json({ error: 'User not found' });
  if (user.role === 'superadmin') return res.status(403).json({ error: 'Cannot delete superadmin' });
  if (req.user.role === 'admin' && user.role !== 'teacher') return res.status(403).json({ error: 'Admins can only delete teachers' });
  db.prepare('DELETE FROM users WHERE id=?').run(req.params.id);
  audit.log(db, { user: req.user, action: audit.ACTIONS.USER_DELETED, targetType: 'User', targetId: user.username, details: `Deleted ${user.role}: ${user.name}`, ip: audit.getIp(req) });
  res.json({ success: true });
});

// ── STUDENTS ROUTES ──
app.get('/api/students', authMiddleware, (req, res) => {
  const { class: cls, search } = req.query;
  let q = 'SELECT * FROM students WHERE 1=1';
  const params = [];
  if (cls) { q += ' AND class=?'; params.push(cls); }
  if (search) {
    // Support searching by Student ID (ASS-XXXX) or name
    if (/^ASS-/i.test(search.trim())) {
      q += ' AND student_id LIKE ?';
      params.push(search.trim().toUpperCase() + '%');
    } else {
      q += ' AND name LIKE ?';
      params.push('%' + search + '%');
    }
  }
  q += ' ORDER BY class, num';
  res.json(db.prepare(q).all(...params));
});

app.post('/api/students', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const s = req.body;
  // student_id is always system-generated — never accepted from client
  try {
    const newStudentId = generateStudentId();
    const result = db.prepare(`INSERT INTO students (student_id,num,name,class,gender,dob,guardian_name,guardian_phone,father_phone,mother_name,mother_phone,fee_amount,fee_type)
      VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)`).run(newStudentId,s.num||null,s.name,s.class,s.gender||'',s.dob||'',s.guardian_name||'',s.guardian_phone||'',s.father_phone||'',s.mother_name||'',s.mother_phone||'',s.fee_amount||0,s.fee_type||'Full payment');
    audit.log(db, { user: req.user, action: audit.ACTIONS.STUDENT_CREATED, targetType: 'Student', targetId: newStudentId, details: `Name: ${s.name}, Class: ${s.class}`, ip: audit.getIp(req) });
    res.json({ success: true, id: result.lastInsertRowid, student_id: newStudentId });
  } catch(e) { res.status(400).json({ error: e.message }); }
});

