// ── ATTENDANCE ROUTES ──
app.get('/api/attendance', authMiddleware, (req, res) => {
  const { class: cls, date } = req.query;
  if (!cls || !date) return res.status(400).json({ error: 'class and date required' });
  const records = db.prepare('SELECT student_id, status FROM attendance WHERE class=? AND date=?').all(cls, date);
  const lock = db.prepare('SELECT locked FROM attendance_locks WHERE class=? AND date=?').get(cls, date);
  res.json({ records, locked: lock?.locked || 0 });
});

app.post('/api/attendance', authMiddleware, (req, res) => {
  const { class: cls, date, records } = req.body;
  if (!cls || !date || !records) return res.status(400).json({ error: 'Missing fields' });
  const lock = db.prepare('SELECT locked FROM attendance_locks WHERE class=? AND date=?').get(cls, date);
  if (lock?.locked) return res.status(403).json({ error: 'Attendance is locked' });
  const upsert = db.prepare(`INSERT INTO attendance (class,date,student_id,status,marked_by)
    VALUES (?,?,?,?,?) ON CONFLICT(class,date,student_id) DO UPDATE SET status=excluded.status, marked_by=excluded.marked_by`);
  const saveAll = db.transaction(() => {
    for (const [sid, status] of Object.entries(records)) {
      upsert.run(cls, date, parseInt(sid), status, req.user.username);
    }
  });
  saveAll();
  const recCount = Object.keys(records).length;
  audit.log(db, { user: req.user, action: audit.ACTIONS.ATTENDANCE_SAVED, targetType: 'Attendance', targetId: `${cls}/${date}`, details: `Saved ${recCount} records for ${cls} on ${date}`, ip: audit.getIp(req) });
  res.json({ success: true });
});

app.post('/api/attendance/lock', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const { class: cls, date, locked } = req.body;
  db.prepare(`INSERT INTO attendance_locks (class,date,locked) VALUES (?,?,?)
    ON CONFLICT(class,date) DO UPDATE SET locked=excluded.locked`).run(cls, date, locked?1:0);
  const lockAction = locked ? audit.ACTIONS.ATTENDANCE_LOCKED : audit.ACTIONS.ATTENDANCE_UNLOCKED;
  audit.log(db, { user: req.user, action: lockAction, targetType: 'Attendance', targetId: `${cls}/${date}`, details: `${locked ? 'Locked' : 'Unlocked'} attendance for ${cls} on ${date}`, ip: audit.getIp(req) });
  res.json({ success: true });
});

// Attendance summary for status page
app.get('/api/attendance/summary', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const { date, month } = req.query;
  if (date) {
    const rows = db.prepare(`SELECT class,
      SUM(CASE WHEN status='present' THEN 1 ELSE 0 END) as present,
      SUM(CASE WHEN status='absent' THEN 1 ELSE 0 END) as absent,
      SUM(CASE WHEN status='late' THEN 1 ELSE 0 END) as late,
      COUNT(*) as total
      FROM attendance WHERE date=? GROUP BY class`).all(date);
    res.json(rows);
  } else if (month) {
    const rows = db.prepare(`SELECT class, student_id,
      SUM(CASE WHEN status='present' THEN 1 ELSE 0 END) as present_days,
      SUM(CASE WHEN status='absent' THEN 1 ELSE 0 END) as absent_days,
      COUNT(*) as total_days
      FROM attendance WHERE date LIKE ? GROUP BY class, student_id`).all(month+'%');
    res.json(rows);
  } else {
    res.status(400).json({ error: 'date or month required' });
  }
});

// Class attendance breakdown by month — used by Attendance Status monthly tab
app.get('/api/attendance/class-month', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const { month } = req.query;
  if (!month) return res.status(400).json({ error: 'month required' });
  const rows = db.prepare(`
    SELECT a.class,
      COUNT(DISTINCT a.date) as days_recorded,
      SUM(CASE WHEN a.status='present' THEN 1 ELSE 0 END) as present,
      SUM(CASE WHEN a.status='absent'  THEN 1 ELSE 0 END) as absent,
      SUM(CASE WHEN a.status='late'    THEN 1 ELSE 0 END) as late,
      COUNT(*) as total_records
    FROM attendance a
    WHERE a.date LIKE ?
    GROUP BY a.class
    ORDER BY a.class
  `).all(month + '%');
  res.json(rows);
});

