app.post('/api/exams', authMiddleware, (req, res) => {
  const { class: cls, subject, exam_type, marks } = req.body;
  if (!cls || !subject || !exam_type || !marks) return res.status(400).json({ error: 'Missing fields' });
  const academic_year = req.body.academic_year || db.prepare("SELECT value FROM academic_settings WHERE key='current_year'").get()?.value || '2025-2026';
  const upsert = db.prepare(`INSERT INTO exam_marks (class,subject,exam_type,academic_year,student_id,mark,entered_by)
    VALUES (?,?,?,?,?,?,?) ON CONFLICT(class,subject,exam_type,academic_year,student_id) DO UPDATE SET mark=excluded.mark, entered_by=excluded.entered_by, updated_at=CURRENT_TIMESTAMP`);
  const saveAll = db.transaction(() => {
    for (const [sid, mark] of Object.entries(marks)) {
      if (mark !== null && mark !== undefined && mark !== '')
        upsert.run(cls, subject, exam_type, academic_year, parseInt(sid), parseFloat(mark), req.user.username);
    }
  });
  saveAll();
  const markCount = Object.keys(marks).length;
  audit.log(db, { user: req.user, action: audit.ACTIONS.MARKS_SAVED, targetType: 'Exam', targetId: `${cls}/${subject}/${exam_type}`, details: `Saved ${markCount} marks for ${subject} (${exam_type}) in ${cls}`, ip: audit.getIp(req) });
  res.json({ success: true });
});

// ── EDIT MARK ──
app.put('/api/exams/:id', authMiddleware, requireRole('superadmin','admin'), (req, res) => {
  const { mark } = req.body;
  if (mark === undefined) return res.status(400).json({ error: 'mark required' });
  const existing = db.prepare('SELECT * FROM exam_marks WHERE id=?').get(req.params.id);
  if (!existing) return res.status(404).json({ error: 'Mark not found' });
  db.prepare('UPDATE exam_marks SET mark=?, entered_by=?, updated_at=CURRENT_TIMESTAMP WHERE id=?')
    .run(parseFloat(mark), req.user.username, req.params.id);
  audit.log(db, { user: req.user, action: audit.ACTIONS.MARKS_SAVED, targetType: 'Exam', targetId: `${existing.class}/${existing.subject}/${existing.exam_type}`, details: `Mark updated from ${existing.mark} to ${mark} for student_id ${existing.student_id}`, ip: audit.getIp(req) });
  res.json({ success: true });
});

