const CLASS_PROGRESSION = {
  'Grade 2 Xarunta':'Grade 3 Xarunta',
  'Grade 2 Faraca':'Grade 3 Faraca',
  'Grade 3 Xarunta':'Grade 4 Xarunta',
  'Grade 3 Faraca':'Grade 4 Faraca',
  'Grade 4 Xarunta':'Grade 5 Xarunta',
  'Grade 4 Faraca':'Grade 5 Faraca',
  'Grade 5 Xarunta':'Grade 6',
  'Grade 5 Faraca':'Grade 6',
  'Grade 6':'Grade 7',
  'Grade 7':'Grade 8',
  'Grade 8':'Graduated',
  'KG Xarunta':'Grade 1 Xarunta',
  'KG Faraca':'Grade 1 Faraca',
  'KG Galbeedka':'Grade 1 Galbeedka',
  'Grade 1 Xarunta':'Grade 2 Xarunta',
  'Grade 1 Faraca':'Grade 2 Faraca',
  'Grade 1 Galbeedka':'Grade 2 Xarunta',
};

